<script setup>
import gsap from 'gsap'
import DrawSVGPlugin from 'gsap/DrawSVGPlugin'

gsap.registerPlugin(DrawSVGPlugin)
function float(elId, yVal) {
  return gsap.to(elId, { y: yVal, duration: 2, repeat: -1, yoyo: true, ease: 'sine.inOut' })
}
function blink(elId, toColor) {
  gsap.set(elId, { color: '#ffeb58' })
  return gsap.to(elId, { color: toColor, repeat: -1, duration: 1, yoyo: true })
}

onMounted(() => {
  float('#form', 50)
  float('#lock', -30)
  float('#box-up', -10)
  blink('#box-dots', '#a3d920')
  const arwTl = gsap.timeline({ repeat: -1, repeatDelay: 0.4 })

  arwTl
    .set(['#arrw-above', '#arw-mid', '#arw-below'], { autoAlpha: 0 })
    .to('#arrw-above', { autoAlpha: 1, duration: 0.35 })
    .to('#arw-mid', { autoAlpha: 1, duration: 0.35 }, '>-0.1')
    .to('#arw-below', { autoAlpha: 1, duration: 0.35 }, '>-0.1')
    .to(['#arrw-above', '#arw-mid', '#arw-below'], {
      autoAlpha: 0,
      duration: 0.3,
      delay: 0.4,
    })
})
</script>

